PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?fullname ?course_name WHERE {
  ?professors a :Instructors .
  ?courses a :Courses .
  ?courses p:hasProfessors ?professors .
  ?professors p:name ?fullname .
  ?courses p:course_name ?course_name .
} }
  full: { SELECT ?fullname ?name ?course_name WHERE {
  ?professors a :Instructors .
  ?courses a :Courses .
  ?courses p:hasProfessors ?professors .
  ?disciplines a :Academic_Discipline .
  ?courses p:hasDisciplines ?disciplines .
  ?professors p:name ?fullname .
  ?disciplines p:name ?name .
  ?courses p:course_name ?course_name .
} }
  component_2: { SELECT ?fullname ?name WHERE {
  ?professors a :Instructors .
  ?courses a :Courses .
  ?courses p:hasProfessors ?professors .
  ?disciplines a :Academic_Discipline .
  ?courses p:hasDisciplines ?disciplines .
  ?professors p:name ?fullname .
  ?disciplines p:name ?name .
} }
}

PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name_g ?course_name_g (COUNT(*) AS ?agg) WHERE {
  ?courses a :Courses .
  ?disciplines a :Academic_Discipline .
  ?courses p:hasDisciplines ?disciplines .
  ?disciplines p:name ?name_g .
  ?courses p:course_name ?course_name_g .
}
GROUP BY ?name_g ?course_name_g }
  component: { SELECT ?name_g (COUNT(*) AS ?agg) WHERE {
  ?courses a :Courses .
  ?disciplines a :Academic_Discipline .
  ?courses p:hasDisciplines ?disciplines .
  ?disciplines p:name ?name_g .
}
GROUP BY ?name_g }
  component_2: { SELECT ?course_name_g (COUNT(*) AS ?agg) WHERE {
  ?courses a :Courses .
  ?courses p:course_name ?course_name_g .
}
GROUP BY ?course_name_g }
}
